code:
-- Add new column
ALTER TABLE STUDENT ADD Phone VARCHAR2(15);

-- Modify existing column
ALTER TABLE STUDENT MODIFY Name VARCHAR2(100);

-- Add constraint
ALTER TABLE STUDENT ADD CONSTRAINT Stu_Age_Chk CHECK (Age >= 18);

-- Drop column
ALTER TABLE STUDENT DROP COLUMN Phone;

-- Drop constraint
ALTER TABLE STUDENT DROP CONSTRAINT Stu_Age_Chk;

-- Rename table
RENAME STUDENT TO STUDENTS;

-- DROP: Removes entire table structure permanently
DROP TABLE STUDENT;

-- TRUNCATE: Removes all rows, keeps structure
TRUNCATE TABLE STUDENT;

-- DELETE: Removes rows one by one, can be rolled back
DELETE FROM STUDENT WHERE Age < 18;

-- To rollback DELETE (in transaction)
COMMIT; -- or ROLLBACK;

-- Create simple index
CREATE INDEX idx_student_name ON STUDENT(Name);

-- Create unique index
CREATE UNIQUE INDEX idx_student_email ON STUDENT(Email);

-- Create composite index
CREATE INDEX idx_student_course_age ON STUDENT(Course_ID, Age);

-- Drop index
DROP INDEX idx_student_name;

-- Create parent table first
CREATE TABLE DEPARTMENT (
 Dept_ID NUMBER(3) PRIMARY KEY,
 Dept_Name VARCHAR2(50) NOT NULL
);

-- Create child table with foreign key
CREATE TABLE EMPLOYEE (
 Emp_ID NUMBER(5) PRIMARY KEY,
 Emp_Name VARCHAR2(50) NOT NULL,
 Dept_ID NUMBER(3) REFERENCES DEPARTMENT(Dept_ID),
 Salary NUMBER(10,2)
);

-- Create with ON DELETE CASCADE
CREATE TABLE EMPLOYEE2 (
 Emp_ID NUMBER(5) PRIMARY KEY,
 Emp_Name VARCHAR2(50) NOT NULL,
 Dept_ID NUMBER(3) REFERENCES DEPARTMENT(Dept_ID) ON DELETE CASCADE,
 Salary NUMBER(10,2)
);

-- Numeric types
CREATE TABLE sample_numeric (
 col1 NUMBER(5), -- 5 digits total
 col2 NUMBER(5,2), -- 5 digits, 2 decimal places
 col3 INTEGER,
 col4 FLOAT
);

-- Character types
CREATE TABLE sample_char (
 col1 CHAR(10), -- Fixed: stores 'Hi' as 'Hi '
 col2 VARCHAR2(10), -- Variable: stores 'Hi' as 'Hi'
 col3 CLOB -- Large text
);

-- Date/Time types
CREATE TABLE sample_date (
 col1 DATE, -- Date and time
 col2 TIMESTAMP -- Date with fractional seconds
);

-- Binary types
CREATE TABLE sample_blob (
 col1 BLOB, -- Binary data (images, etc.)
 col2 RAW(100) -- Raw binary
);
